      "一言要約": "新しさ×実行力"
    },
    {
      "概念": "アイデア量産効果",
      "定義": "多作ほど当たりの確率が上がり、名作は大量生産の副産物になりやすい。",
      "一言要約": "量が質を生む"
    },
    {
      "概念": "アイデア選別",
      "定義": "創作者本人はヒット予測が苦手で、同僚や対象顧客の評価が相対的に当たりやすい。",
      "一言要約": "他者目線で選ぶ"
    },
    {
      "概念": "戦略的先延ばし",
      "定義": "締切前に意図的な余白をつくり、熟成と連結で独創性を高める。",
      "一言要約": "遅らせて熟す"
    },
    {
      "概念": "中庸なリスクとポートフォリオ",
      "定義": "生活基盤を守りつつ一部で大胆に賭けることで挑戦を持続可能にする。",
      "一言要約": "攻めと守りの両立"
    },
    {
      "概念": "二番手優位",
      "定義": "先行者の失敗から学び、普及・教育コストを抑えて拡張する後発戦略。",
      "一言要約": "学びの後出し"
    },
    {
      "概念": "ディスアーム型説得",
      "定義": "弱みやリスクを先に示し、問いを用いて相手の抵抗を下げ賛同を得る。",
      "一言要約": "先に武装解除"
    },
    {
      "概念": "トロイの木馬的フレーミング",
      "定義": "急進的な中身を馴染みの枠組み・段階的提案に包み、受容性を高める。",
      "一言要約": "急進を穏当に包む"
    },
    {
      "概念": "本物の異論と悪魔の代弁者",
      "定義": "役割上の反対ではなく信念に基づく異論が思考を深める。",
      "一言要約": "本気の反対が効く"
    },
    {
      "概念": "文化的貢献採用",
      "定義": "“フィット”よりも新たな価値観や視点で文化を拡張する人を重視する採用。",
      "一言要約": "文化を進化させる人材"
    },
    {
      "概念": "後悔の非対称性",
      "定義": "短期は行動の失敗を悔い、長期は挑戦しなかった不作為を悔いる傾向。",
      "一言要約": "やらない後悔が残る"
    },
    {
      "概念": "地位と発言の関係",
      "定義": "中位の地位は順応圧が強く発言が難しいが、信用と同盟で越えられる。",
      "一言要約": "信用が声を守る"
    }
    ],
